public object FfiConverterTypeFireCoreHandle: FfiConverter<FireCoreHandle, Pointer> {

    override fun lower(value: FireCoreHandle): Pointer {
        return value.uniffiClonePointer()
    }

    override fun lift(value: Pointer): FireCoreHandle {
        return FireCoreHandle(value)
    }

    override fun read(buf: ByteBuffer): FireCoreHandle {
        // The Rust code always writes pointers as 8 bytes, and will
        // fail to compile if they don't fit.
        return lift(Pointer(buf.getLong()))
    }

    override fun allocationSize(value: FireCoreHandle) = 8UL

    override fun write(value: FireCoreHandle, buf: ByteBuffer) {
        // The Rust code always expects pointers written as 8 bytes,
        // and will fail to compile if they don't fit.
        buf.putLong(Pointer.nativeValue(lower(value)))
    }
}



