sealed class FireUniFfiException: kotlin.Exception() {
    
    class Configuration(
        
        val `details`: kotlin.String
        ) : FireUniFfiException() {
        override val message
            get() = "details=${ `details` }"
    }
    
    class Validation(
        
        val `details`: kotlin.String
        ) : FireUniFfiException() {
        override val message
            get() = "details=${ `details` }"
    }
    
    class Authentication(
        
        val `details`: kotlin.String
        ) : FireUniFfiException() {
        override val message
            get() = "details=${ `details` }"
    }
    
    class Network(
        
        val `details`: kotlin.String
        ) : FireUniFfiException() {
        override val message
            get() = "details=${ `details` }"
    }
    
    class HttpStatus(
        
        val `operation`: kotlin.String, 
        
        val `status`: kotlin.UShort, 
        
        val `body`: kotlin.String
        ) : FireUniFfiException() {
        override val message
            get() = "operation=${ `operation` }, status=${ `status` }, body=${ `body` }"
    }
    
    class Storage(
        
        val `details`: kotlin.String
        ) : FireUniFfiException() {
        override val message
            get() = "details=${ `details` }"
    }
    
    class Serialization(
        
        val `details`: kotlin.String
        ) : FireUniFfiException() {
        override val message
            get() = "details=${ `details` }"
    }
    
    class Runtime(
        
        val `details`: kotlin.String
        ) : FireUniFfiException() {
        override val message
            get() = "details=${ `details` }"
    }
    
    class Internal(
        
        val `details`: kotlin.String
        ) : FireUniFfiException() {
        override val message
            get() = "details=${ `details` }"
    }
    

    companion object ErrorHandler : UniffiRustCallStatusErrorHandler<FireUniFfiException> {
        override fun lift(error_buf: RustBuffer.ByValue): FireUniFfiException = FfiConverterTypeFireUniFfiError.lift(error_buf)
    }

    
}

/**
 * @suppress
 */
public object FfiConverterTypeFireUniFfiError : FfiConverterRustBuffer<FireUniFfiException> {
    override fun read(buf: ByteBuffer): FireUniFfiException {
        

        return when(buf.getInt()) {
            1 -> FireUniFfiException.Configuration(
                FfiConverterString.read(buf),
                )
            2 -> FireUniFfiException.Validation(
                FfiConverterString.read(buf),
                )
            3 -> FireUniFfiException.Authentication(
                FfiConverterString.read(buf),
                )
            4 -> FireUniFfiException.Network(
                FfiConverterString.read(buf),
                )
            5 -> FireUniFfiException.HttpStatus(
                FfiConverterString.read(buf),
                FfiConverterUShort.read(buf),
                FfiConverterString.read(buf),
                )
            6 -> FireUniFfiException.Storage(
                FfiConverterString.read(buf),
                )
            7 -> FireUniFfiException.Serialization(
                FfiConverterString.read(buf),
                )
            8 -> FireUniFfiException.Runtime(
                FfiConverterString.read(buf),
                )
            9 -> FireUniFfiException.Internal(
                FfiConverterString.read(buf),
                )
            else -> throw RuntimeException("invalid error enum value, something is very wrong!!")
        }
    }

    override fun allocationSize(value: FireUniFfiException): ULong {
        return when(value) {
            is FireUniFfiException.Configuration -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`details`)
            )
            is FireUniFfiException.Validation -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`details`)
            )
            is FireUniFfiException.Authentication -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`details`)
            )
            is FireUniFfiException.Network -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`details`)
            )
            is FireUniFfiException.HttpStatus -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`operation`)
                + FfiConverterUShort.allocationSize(value.`status`)
                + FfiConverterString.allocationSize(value.`body`)
            )
            is FireUniFfiException.Storage -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`details`)
            )
            is FireUniFfiException.Serialization -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`details`)
            )
            is FireUniFfiException.Runtime -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`details`)
            )
            is FireUniFfiException.Internal -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`details`)
            )
        }
    }

    override fun write(value: FireUniFfiException, buf: ByteBuffer) {
        when(value) {
            is FireUniFfiException.Configuration -> {
                buf.putInt(1)
                FfiConverterString.write(value.`details`, buf)
                Unit
            }
            is FireUniFfiException.Validation -> {
                buf.putInt(2)
                FfiConverterString.write(value.`details`, buf)
                Unit
            }
            is FireUniFfiException.Authentication -> {
                buf.putInt(3)
                FfiConverterString.write(value.`details`, buf)
                Unit
            }
            is FireUniFfiException.Network -> {
                buf.putInt(4)
                FfiConverterString.write(value.`details`, buf)
                Unit
            }
            is FireUniFfiException.HttpStatus -> {
                buf.putInt(5)
                FfiConverterString.write(value.`operation`, buf)
                FfiConverterUShort.write(value.`status`, buf)
                FfiConverterString.write(value.`body`, buf)
                Unit
            }
            is FireUniFfiException.Storage -> {
                buf.putInt(6)
                FfiConverterString.write(value.`details`, buf)
                Unit
            }
            is FireUniFfiException.Serialization -> {
                buf.putInt(7)
                FfiConverterString.write(value.`details`, buf)
                Unit
            }
            is FireUniFfiException.Runtime -> {
                buf.putInt(8)
                FfiConverterString.write(value.`details`, buf)
                Unit
            }
            is FireUniFfiException.Internal -> {
                buf.putInt(9)
                FfiConverterString.write(value.`details`, buf)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }

}




